// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// Forumline discovery manifest
	// (GET /.well-known/forumline-manifest.json)
	GetManifest(ctx context.Context, request GetManifestRequestObject) (GetManifestResponseObject, error)
	// Import forum data
	// (POST /api/admin/import)
	ImportData(ctx context.Context, request ImportDataRequestObject) (ImportDataResponseObject, error)
	// Get admin statistics
	// (GET /api/admin/stats)
	GetAdminStats(ctx context.Context, request GetAdminStatsRequestObject) (GetAdminStatsResponseObject, error)
	// List all users (admin)
	// (GET /api/admin/users)
	ListAdminUsers(ctx context.Context, request ListAdminUsersRequestObject) (ListAdminUsersResponseObject, error)
	// Upload an avatar or image
	// (POST /api/avatars/upload)
	UploadAvatar(ctx context.Context, request UploadAvatarRequestObject) (UploadAvatarResponseObject, error)
	// List bookmarks
	// (GET /api/bookmarks)
	ListBookmarks(ctx context.Context, request ListBookmarksRequestObject) (ListBookmarksResponseObject, error)
	// Bookmark a thread
	// (POST /api/bookmarks)
	AddBookmark(ctx context.Context, request AddBookmarkRequestObject) (AddBookmarkResponseObject, error)
	// Remove bookmark by bookmark ID
	// (DELETE /api/bookmarks/by-id/{id})
	RemoveBookmarkById(ctx context.Context, request RemoveBookmarkByIdRequestObject) (RemoveBookmarkByIdResponseObject, error)
	// Remove bookmark by thread ID
	// (DELETE /api/bookmarks/{threadId})
	RemoveBookmark(ctx context.Context, request RemoveBookmarkRequestObject) (RemoveBookmarkResponseObject, error)
	// Check bookmark status
	// (GET /api/bookmarks/{threadId}/status)
	GetBookmarkStatus(ctx context.Context, request GetBookmarkStatusRequestObject) (GetBookmarkStatusResponseObject, error)
	// List all categories
	// (GET /api/categories)
	ListCategories(ctx context.Context, request ListCategoriesRequestObject) (ListCategoriesResponseObject, error)
	// Get category by slug
	// (GET /api/categories/{slug})
	GetCategoryBySlug(ctx context.Context, request GetCategoryBySlugRequestObject) (GetCategoryBySlugResponseObject, error)
	// List threads by category
	// (GET /api/categories/{slug}/threads)
	ListThreadsByCategory(ctx context.Context, request ListThreadsByCategoryRequestObject) (ListThreadsByCategoryResponseObject, error)
	// Unfollow a category
	// (DELETE /api/channel-follows)
	UnfollowChannel(ctx context.Context, request UnfollowChannelRequestObject) (UnfollowChannelResponseObject, error)
	// List followed categories
	// (GET /api/channel-follows)
	ListChannelFollows(ctx context.Context, request ListChannelFollowsRequestObject) (ListChannelFollowsResponseObject, error)
	// Follow a category
	// (POST /api/channel-follows)
	FollowChannel(ctx context.Context, request FollowChannelRequestObject) (FollowChannelResponseObject, error)
	// List all chat channels
	// (GET /api/channels)
	ListChannels(ctx context.Context, request ListChannelsRequestObject) (ListChannelsResponseObject, error)
	// Send a chat message by channel ID
	// (POST /api/channels/_by-id/{id}/messages)
	SendChatMessageByID(ctx context.Context, request SendChatMessageByIDRequestObject) (SendChatMessageByIDResponseObject, error)
	// List chat messages
	// (GET /api/channels/{slug}/messages)
	ListChatMessages(ctx context.Context, request ListChatMessagesRequestObject) (ListChatMessagesResponseObject, error)
	// Send a chat message
	// (POST /api/channels/{slug}/messages)
	SendChatMessage(ctx context.Context, request SendChatMessageRequestObject) (SendChatMessageResponseObject, error)
	// Stream chat messages (SSE)
	// (GET /api/channels/{slug}/stream)
	StreamChatMessages(ctx context.Context, request StreamChatMessagesRequestObject) (StreamChatMessagesResponseObject, error)
	// Get forum configuration
	// (GET /api/config)
	GetConfig(ctx context.Context, request GetConfigRequestObject) (GetConfigResponseObject, error)
	// Start login flow
	// (GET /api/forumline/auth)
	StartLogin(ctx context.Context, request StartLoginRequestObject) (StartLoginResponseObject, error)
	// OAuth callback
	// (GET /api/forumline/auth/callback)
	AuthCallback(ctx context.Context, request AuthCallbackRequestObject) (AuthCallbackResponseObject, error)
	// Log out
	// (DELETE /api/forumline/auth/session)
	Logout(ctx context.Context, request LogoutRequestObject) (LogoutResponseObject, error)
	// Get current session
	// (GET /api/forumline/auth/session)
	GetSession(ctx context.Context, request GetSessionRequestObject) (GetSessionResponseObject, error)
	// Exchange JWT for session (iframe flow)
	// (POST /api/forumline/auth/token-exchange)
	TokenExchange(ctx context.Context, request TokenExchangeRequestObject) (TokenExchangeResponseObject, error)
	// List Forumline-format notifications
	// (GET /api/forumline/notifications)
	ListForumlineNotifications(ctx context.Context, request ListForumlineNotificationsRequestObject) (ListForumlineNotificationsResponseObject, error)
	// Mark a notification as read
	// (POST /api/forumline/notifications/read)
	MarkNotificationRead(ctx context.Context, request MarkNotificationReadRequestObject) (MarkNotificationReadResponseObject, error)
	// Stream notifications (SSE)
	// (GET /api/forumline/notifications/stream)
	StreamNotifications(ctx context.Context, request StreamNotificationsRequestObject) (StreamNotificationsResponseObject, error)
	// Get unread counts
	// (GET /api/forumline/unread)
	GetUnreadCounts(ctx context.Context, request GetUnreadCountsRequestObject) (GetUnreadCountsResponseObject, error)
	// List LiveKit participants
	// (GET /api/livekit)
	GetLiveKitParticipants(ctx context.Context, request GetLiveKitParticipantsRequestObject) (GetLiveKitParticipantsResponseObject, error)
	// Get LiveKit access token
	// (POST /api/livekit)
	GetLiveKitToken(ctx context.Context, request GetLiveKitTokenRequestObject) (GetLiveKitTokenResponseObject, error)
	// List notification preferences
	// (GET /api/notification-preferences)
	ListNotificationPreferences(ctx context.Context, request ListNotificationPreferencesRequestObject) (ListNotificationPreferencesResponseObject, error)
	// Update a notification preference
	// (PUT /api/notification-preferences)
	UpdateNotificationPreference(ctx context.Context, request UpdateNotificationPreferenceRequestObject) (UpdateNotificationPreferenceResponseObject, error)
	// List notifications
	// (GET /api/notifications)
	ListNotifications(ctx context.Context, request ListNotificationsRequestObject) (ListNotificationsResponseObject, error)
	// Mark all notifications as read
	// (POST /api/notifications/read-all)
	MarkAllNotificationsRead(ctx context.Context, request MarkAllNotificationsReadRequestObject) (MarkAllNotificationsReadResponseObject, error)
	// Create a post
	// (POST /api/posts)
	CreatePost(ctx context.Context, request CreatePostRequestObject) (CreatePostResponseObject, error)
	// Get profiles in batch
	// (GET /api/profiles/batch)
	GetProfilesBatch(ctx context.Context, request GetProfilesBatchRequestObject) (GetProfilesBatchResponseObject, error)
	// Get profile by username
	// (GET /api/profiles/by-username/{username})
	GetProfileByUsername(ctx context.Context, request GetProfileByUsernameRequestObject) (GetProfileByUsernameResponseObject, error)
	// Get profile by ID
	// (GET /api/profiles/{id})
	GetProfile(ctx context.Context, request GetProfileRequestObject) (GetProfileResponseObject, error)
	// Create or update profile
	// (PUT /api/profiles/{id})
	UpsertProfile(ctx context.Context, request UpsertProfileRequestObject) (UpsertProfileResponseObject, error)
	// Clear Forumline ID link
	// (DELETE /api/profiles/{id}/forumline-id)
	ClearForumlineId(ctx context.Context, request ClearForumlineIdRequestObject) (ClearForumlineIdResponseObject, error)
	// Search posts
	// (GET /api/search/posts)
	SearchPosts(ctx context.Context, request SearchPostsRequestObject) (SearchPostsResponseObject, error)
	// Search threads
	// (GET /api/search/threads)
	SearchThreads(ctx context.Context, request SearchThreadsRequestObject) (SearchThreadsResponseObject, error)
	// List threads
	// (GET /api/threads)
	ListThreads(ctx context.Context, request ListThreadsRequestObject) (ListThreadsResponseObject, error)
	// Create a thread
	// (POST /api/threads)
	CreateThread(ctx context.Context, request CreateThreadRequestObject) (CreateThreadResponseObject, error)
	// Get thread by ID
	// (GET /api/threads/{id})
	GetThread(ctx context.Context, request GetThreadRequestObject) (GetThreadResponseObject, error)
	// Update a thread
	// (PATCH /api/threads/{id})
	UpdateThread(ctx context.Context, request UpdateThreadRequestObject) (UpdateThreadResponseObject, error)
	// List posts in a thread
	// (GET /api/threads/{id}/posts)
	ListPostsByThread(ctx context.Context, request ListPostsByThreadRequestObject) (ListPostsByThreadResponseObject, error)
	// Stream new posts (SSE)
	// (GET /api/threads/{id}/stream)
	StreamPosts(ctx context.Context, request StreamPostsRequestObject) (StreamPostsResponseObject, error)
	// List posts by user
	// (GET /api/users/{id}/posts)
	ListUserPosts(ctx context.Context, request ListUserPostsRequestObject) (ListUserPostsResponseObject, error)
	// List threads by user
	// (GET /api/users/{id}/threads)
	ListUserThreads(ctx context.Context, request ListUserThreadsRequestObject) (ListUserThreadsResponseObject, error)
	// Clear voice presence
	// (DELETE /api/voice-presence)
	ClearVoicePresence(ctx context.Context, request ClearVoicePresenceRequestObject) (ClearVoicePresenceResponseObject, error)
	// List voice presence
	// (GET /api/voice-presence)
	ListVoicePresence(ctx context.Context, request ListVoicePresenceRequestObject) (ListVoicePresenceResponseObject, error)
	// Set voice presence
	// (PUT /api/voice-presence)
	SetVoicePresence(ctx context.Context, request SetVoicePresenceRequestObject) (SetVoicePresenceResponseObject, error)
	// Stream voice presence changes (SSE)
	// (GET /api/voice-presence/stream)
	StreamVoicePresence(ctx context.Context, request StreamVoicePresenceRequestObject) (StreamVoicePresenceResponseObject, error)
	// List voice rooms
	// (GET /api/voice-rooms)
	ListVoiceRooms(ctx context.Context, request ListVoiceRoomsRequestObject) (ListVoiceRoomsResponseObject, error)
}

type StrictHandlerFunc = strictnethttp.StrictHTTPHandlerFunc
type StrictMiddlewareFunc = strictnethttp.StrictHTTPMiddlewareFunc

type StrictHTTPServerOptions struct {
	RequestErrorHandlerFunc  func(w http.ResponseWriter, r *http.Request, err error)
	ResponseErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: StrictHTTPServerOptions{
		RequestErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		},
		ResponseErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		},
	}}
}

func NewStrictHandlerWithOptions(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc, options StrictHTTPServerOptions) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: options}
}

type strictHandler struct {
	ssi         StrictServerInterface
	middlewares []StrictMiddlewareFunc
	options     StrictHTTPServerOptions
}

// GetManifest operation middleware
func (sh *strictHandler) GetManifest(w http.ResponseWriter, r *http.Request) {
	var request GetManifestRequestObject

	handler := func(ctx context.Context, w http.ResponseWriter, r *http.Request, request interface{}) (interface{}, error) {
		return sh.ssi.GetManifest(ctx, request.(GetManifestRequestObject))
	}
	for _, middleware := range sh.middlewares {
		handler = middleware(handler, "GetManifest")
	}

	response, err := handler(r.Context(), w, r, request)

	if err != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, err)
	} else if validResponse, ok := response.(GetManifestResponseObject); ok {
		if err := validResponse.VisitGetManifestResponse(w); err != nil {
			sh.options.ResponseErrorHandlerFunc(w, r, err)
		}
	} else if response != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, fmt.Errorf("unexpected response type: %T", response))
	}
}

// ImportData operation middleware
func (sh *strictHandler) ImportData(w http.ResponseWriter, r *http.Request) {
	var request ImportDataRequestObject

	var body ImportDataJSONRequestBody
	if err := json.NewDecoder(r.Body).Decode(&body); err != nil {
		sh.options.RequestErrorHandlerFunc(w, r, fmt.Errorf("can't decode JSON body: %w", err))
		return
	}
	request.Body = &body

	handler := func(ctx context.Context, w http.ResponseWriter, r *http.Request, request interface{}) (interface{}, error) {
		return sh.ssi.ImportData(ctx, request.(ImportDataRequestObject))
	}
	for _, middleware := range sh.middlewares {
		handler = middleware(handler, "ImportData")
	}

	response, err := handler(r.Context(), w, r, request)

	if err != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, err)
	} else if validResponse, ok := response.(ImportDataResponseObject); ok {
		if err := validResponse.VisitImportDataResponse(w); err != nil {
			sh.options.ResponseErrorHandlerFunc(w, r, err)
		}
	} else if response != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, fmt.Errorf("unexpected response type: %T", response))
	}
}

